SELECT r.id, r.dormitory_id, r.room_number, r.capacity, r.current_occupancy, r.daily_rate, r.room_type, r.ac_type, r.memo1, r.memo2, r.memo3, r.status, r.version, r.create_by, r.create_time, r.update_by, r.update_time, d.dorm_name, d.dorm_condition, d.region FROM tbl_room r LEFT JOIN tbl_dormitory d ON r.dormitory_id = d.id WHERE r.status = 1 AND r.current_occupancy < r.capacity
AND r.dormitory_id = #{dormitoryId}
AND (d.dorm_condition = #{gender} OR d.dorm_condition = 'ANY')
ORDER BY d.region ASC, d.dorm_name ASC, r.room_number ASC
LIMIT #{offset}, #{limit}

